// --- i18n Engine ---
let currentLang = 'en';

function detectLanguage() {
  const params = new URLSearchParams(window.location.search);
  const urlLang = params.get('lang');
  if (urlLang && I18N[urlLang]) return urlLang;
  const saved = localStorage.getItem('seoscore-lang');
  if (saved && I18N[saved]) return saved;
  const nav = (navigator.language || '').slice(0, 2).toLowerCase();
  if (I18N[nav]) return nav;
  return 'en';
}

function applyTranslations(lang) {
  currentLang = lang;
  const t = I18N[lang] || I18N.en;
  document.querySelectorAll('[data-i18n]').forEach(el => {
    const key = el.getAttribute('data-i18n');
    if (t[key]) {
      if (key.endsWith('_html') || /<[a-z]+[\s>/]/i.test(t[key])) el.innerHTML = t[key];
      else el.textContent = t[key];
    }
  });
  document.querySelectorAll('[data-i18n-placeholder]').forEach(el => {
    const key = el.getAttribute('data-i18n-placeholder');
    if (t[key]) el.placeholder = t[key];
  });
  document.documentElement.lang = lang;
  localStorage.setItem('seoscore-lang', lang);

  // Update lang switcher UI
  const btn = document.getElementById('langCurrent');
  if (btn) btn.textContent = lang.toUpperCase();
  document.querySelectorAll('.lang-option').forEach(opt => {
    opt.classList.toggle('active', opt.dataset.lang === lang);
  });
}

function getTranslation(key) {
  return (I18N[currentLang] || I18N.en)[key] || I18N.en[key] || key;
}
